// @vitest-environment node
import { describe, it, expect } from "vitest";
import { canonicalMessage } from "./canonicalSign";

const OWNER = "aa".repeat(32);
const hex = (u: Uint8Array) => Buffer.from(u).toString("hex");

// Golden vectors generated by chain/agentic/testnet/signing.py::canonical_message
// (nonce=7, owner="aa"*32). Wallet-index keys stripped; transact amount = microAGNTC.
const GOLDEN: Record<string, [string, Record<string, unknown>, string]> = {
  secure:   ["secure",   { duration_blocks: 10 },
    ""],
  claim:    ["claim",    { stake: 200, x: 3, y: -2 },
    ""],
  transact: ["transact", { amount: 5500000, recipient_name: "alice", recipient_wallet: null },
    ""],
};

describe("canonicalMessage byte-parity with Python", () => {
  for (const [name, [action, params, expected]] of Object.entries(GOLDEN)) {
    it(`matches the Python golden vector for ${name}`, () => {
      expect(hex(canonicalMessage(action, params, OWNER, 7))).toBe(expected);
    });
  }

  it("strips wallet-index keys from params", () => {
    const withKeys = { wallet_index: 9, sender_wallet: 1, self_wallet: 2, duration_blocks: 10 };
    expect(hex(canonicalMessage("secure", withKeys, OWNER, 7))).toBe(GOLDEN.secure[2]);
  });

  it("sorts nested object keys recursively", () => {
    const a = canonicalMessage("message", { b: 1, a: { y: 2, x: 1 } }, OWNER, 0);
    const b = canonicalMessage("message", { a: { x: 1, y: 2 }, b: 1 }, OWNER, 0);
    expect(hex(a)).toBe(hex(b));
  });
});
